import React from 'react';

type JobEventFailReasonProps = {
  status: string;
  lastError?: string | null;
};

const FAIL_STATUSES = new Set(['Failed', 'DeadLetter']);

export const JobEventFailReason: React.FC<JobEventFailReasonProps> = ({ status, lastError }) => {
  if (!lastError)
    return <span style={{ color: '#94a3b8' }}>—</span>;

  if (!FAIL_STATUSES.has(status) && status !== 'Processing')
    return <span style={{ color: '#94a3b8' }}>—</span>;

  const short = lastError.length > 80 ? `${lastError.slice(0, 77)}…` : lastError;

  return (
    <span
      title={lastError}
      style={{
        fontSize: 12,
        color: '#b91c1c',
        display: 'block',
        maxWidth: 220,
        overflow: 'hidden',
        textOverflow: 'ellipsis',
        whiteSpace: 'nowrap',
      }}
    >
      {short}
    </span>
  );
};
