import React from 'react';
import { StatsCard, StatsCardsGrid } from '../../../../ui';

export interface AccountsStats {
  total:    number;
  active:   number;
  inactive: number;
  admin:    number;    // kept for future use when Auth API exposes role stats
  manager:  number;
}

interface AccountsStatsCardsProps {
  stats:    AccountsStats;
  loading?: boolean;
}

export const AccountsStatsCards: React.FC<AccountsStatsCardsProps> = ({ stats, loading }) => (
  <StatsCardsGrid>
    <StatsCard label="Tổng tài khoản"  value={stats.total}    variant="total"   loading={loading} />
    <StatsCard label="Đang hoạt động"  value={stats.active}   variant="success" loading={loading} />
    <StatsCard label="Vô hiệu hóa"     value={stats.inactive} variant="gray"    loading={loading} />
  </StatsCardsGrid>
);
