import React from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, Pagination, TableCard } from '../../ui';
import {
  jobsService,
  type DataSyncCheckpointItem,
  type DataSyncRunDetail,
  type DataSyncRunListItem,
} from '../../services/jobs';
import { useAppToast } from '@linm-soft/common-components';
import JobsListToolbar from './JobsListToolbar';
import { JobExternalSyncRunDetailPanel } from './components/JobExternalSyncRunDetailPanel';
import { filterBySearchQuery } from './jobsListFilterUtils';
import {
  buildErrorMessageMap,
  connectorLabel,
  formatCheckpointSummaryHint,
  formatExternalRunStatsLine,
  resolveExternalRunDisplayStatus,
} from './externalSyncRunDisplay';
import { ExternalSyncCheckpointErrorModal, truncateExternalErrorPreview } from './components/ExternalSyncCheckpointErrorModal';
import { displayExternalRunStatus, jobStatusColor } from './jobStatusDisplay';
import styles from './JobInternalPage.module.css';

const RUNNING_STATUSES = new Set(['Running']);
const RUNS_PAGE_SIZE = 20;
const CHECKPOINT_PAGE_SIZE = 50;

const formatDate = (iso: string) => new Date(iso).toLocaleString('vi-VN');

const ExternalSyncRunsPage: React.FC = () => {
  useNavTitle('Theo dõi sync ngoài (REVA FM)');
  const toast = useAppToast();
  const [searchParams, setSearchParams] = useSearchParams();

  const [runs, setRuns] = React.useState<DataSyncRunListItem[]>([]);
  const [runsTotal, setRunsTotal] = React.useState(0);
  const [runsPage, setRunsPage] = React.useState(1);
  const [runSearchQuery, setRunSearchQuery] = React.useState('');
  const [selectedRunId, setSelectedRunId] = React.useState<string | null>(searchParams.get('runId'));
  const [runDetail, setRunDetail] = React.useState<DataSyncRunDetail | null>(null);
  const [checkpoints, setCheckpoints] = React.useState<DataSyncCheckpointItem[]>([]);
  const [checkpointsTotal, setCheckpointsTotal] = React.useState(0);
  const [checkpointPage, setCheckpointPage] = React.useState(1);
  const [checkpointStatus, setCheckpointStatus] = React.useState('');
  const [checkpointSearchQuery, setCheckpointSearchQuery] = React.useState('');
  const [loadingRuns, setLoadingRuns] = React.useState(true);
  const [loadingDetail, setLoadingDetail] = React.useState(false);
  const [loadingCheckpoints, setLoadingCheckpoints] = React.useState(false);
  const [checkpointLoadError, setCheckpointLoadError] = React.useState<string | null>(null);
  const [errorModalCheckpoint, setErrorModalCheckpoint] = React.useState<DataSyncCheckpointItem | null>(null);

  const loadRuns = React.useCallback(() => {
    setLoadingRuns(true);
    jobsService
      .getDataSyncRuns(runsPage, RUNS_PAGE_SIZE, 'External')
      .then((r) => {
        setRuns(r.items);
        setRunsTotal(r.total);
      })
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoadingRuns(false));
  }, [runsPage, toast]);

  const loadDetail = React.useCallback(
    (runId: string) => {
      setLoadingDetail(true);
      return jobsService
        .getDataSyncRun(runId)
        .then(setRunDetail)
        .catch((e: Error) => {
          toast.error(e.message);
          setRunDetail(null);
        })
        .finally(() => setLoadingDetail(false));
    },
    [toast],
  );

  const loadCheckpoints = React.useCallback(
    (runId: string) => {
      setLoadingCheckpoints(true);
      setCheckpointLoadError(null);
      return jobsService
        .getRunCheckpoints(runId, checkpointPage, CHECKPOINT_PAGE_SIZE, checkpointStatus || undefined)
        .then((r) => {
          setCheckpoints(r.items);
          setCheckpointsTotal(r.total);
        })
        .catch((e: Error) => {
          setCheckpoints([]);
          setCheckpointsTotal(0);
          setCheckpointLoadError(e.message);
          toast.error(e.message);
        })
        .finally(() => setLoadingCheckpoints(false));
    },
    [checkpointPage, checkpointStatus, toast],
  );

  React.useEffect(() => {
    loadRuns();
  }, [loadRuns]);

  React.useEffect(() => {
    const fromUrl = searchParams.get('runId');
    if (fromUrl && fromUrl !== selectedRunId) {
      setSelectedRunId(fromUrl);
    }
  }, [searchParams, selectedRunId]);

  React.useEffect(() => {
    if (!selectedRunId) {
      setRunDetail(null);
      setCheckpoints([]);
      return;
    }
    setRunDetail(null);
    loadDetail(selectedRunId);
  }, [selectedRunId, loadDetail]);

  React.useEffect(() => {
    if (!selectedRunId) return;
    loadCheckpoints(selectedRunId);
  }, [selectedRunId, checkpointPage, checkpointStatus, loadCheckpoints]);

  React.useEffect(() => {
    if (!selectedRunId || !runDetail || !RUNNING_STATUSES.has(runDetail.status)) return undefined;
    const timer = setInterval(() => {
      loadDetail(selectedRunId);
      loadCheckpoints(selectedRunId);
      loadRuns();
    }, 4000);
    return () => clearInterval(timer);
  }, [selectedRunId, runDetail?.status, loadDetail, loadCheckpoints, loadRuns]);

  const selectRun = (runId: string) => {
    setSelectedRunId(runId);
    setCheckpointPage(1);
    setCheckpointSearchQuery('');
    setCheckpointStatus('');
    setCheckpointLoadError(null);
    setSearchParams({ runId });
  };

  const filteredRuns = React.useMemo(
    () =>
      filterBySearchQuery(runs, runSearchQuery, (r) =>
        [r.id, r.status, r.setsRequested.join(' '), formatDate(r.startedAtUtc), String(r.progressPercent)].join(
          ' ',
        ),
      ),
    [runs, runSearchQuery],
  );

  const filteredCheckpoints = React.useMemo(
    () =>
      filterBySearchQuery(checkpoints, checkpointSearchQuery, (c) =>
        [c.setName, c.documentKey, c.status, formatDate(c.updatedAtUtc)].join(' '),
      ),
    [checkpoints, checkpointSearchQuery],
  );

  const runsPages = Math.max(1, Math.ceil(runsTotal / RUNS_PAGE_SIZE));
  const checkpointPages = Math.max(1, Math.ceil(checkpointsTotal / CHECKPOINT_PAGE_SIZE));
  const errorByDocument = React.useMemo(
    () => buildErrorMessageMap(runDetail?.errorSamples, checkpoints),
    [runDetail?.errorSamples, checkpoints],
  );

  const openErrorDetail = (checkpoint: DataSyncCheckpointItem) => {
    setErrorModalCheckpoint(checkpoint);
  };

  return (
    <div data-testid="external-sync-runs-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/external-sync">Cấu hình sync REVA</Link>
      </p>

      <p style={{ color: '#555', marginBottom: 16 }}>
        Theo dõi sync POS/REVA FM: chọn run bên trái → xem tóm tắt convert, đơn vị, lỗi; bảng checkpoint liệt kê từng
        chứng từ. Cấu hình connector tại{' '}
        <Link to="/admin/jobs/external-sync">Cấu hình sync REVA</Link>.
      </p>

      <div className={`${styles.shell} ${styles.shellSplitPane}`}>
        <div className={styles.splitLayout}>
          <div className={styles.splitPaneCard}>
            <TableCard
              listShell
              header={
                <div>
                  <h4 className={styles.listHeaderTitle}>Danh sách run</h4>
                  <p className={styles.listHint}>Tìm theo trạng thái, connector hoặc run id.</p>
                  <JobsListToolbar
                    searchQuery={runSearchQuery}
                    onSearchChange={setRunSearchQuery}
                    searchPlaceholder="Tìm run…"
                    searchTestId="external-runs-search"
                    onRefresh={loadRuns}
                    refreshDisabled={loadingRuns}
                    totalCount={runs.length}
                    filteredCount={filteredRuns.length}
                    loading={loadingRuns}
                    itemLabel="run"
                  />
                </div>
              }
              footer={
                runsPages > 1 ? (
                  <Pagination
                    currentPage={runsPage}
                    totalPages={runsPages}
                    totalCount={runsTotal}
                    pageSize={RUNS_PAGE_SIZE}
                    itemLabel="run"
                    onPageChange={setRunsPage}
                  />
                ) : undefined
              }
            >
              {loadingRuns && runs.length === 0 ? (
                <p className={styles.gridLoading}>Đang tải…</p>
              ) : filteredRuns.length === 0 ? (
                <p className={styles.gridEmpty}>
                  {runSearchQuery.trim() ? 'Không tìm thấy run phù hợp trên trang này.' : 'Chưa có run nào.'}
                </p>
              ) : (
                <ul className={styles.runList}>
                  {filteredRuns.map((r) => {
                    const displayStatus = resolveExternalRunDisplayStatus({
                      status: r.status,
                      checkpointSummary: undefined,
                    });
                    const failed = r.documentsFailed ?? 0;
                    const statsLine = formatExternalRunStatsLine(r);
                    return (
                    <li key={r.id}>
                      <button
                        type="button"
                        onClick={() => selectRun(r.id)}
                        className={`${styles.runItemBtn} ${
                          selectedRunId === r.id ? styles.runItemBtnSelected : ''
                        }`}
                      >
                        <div style={{ display: 'flex', justifyContent: 'space-between', gap: 8 }}>
                          <strong style={{ color: jobStatusColor(displayStatus) }}>
                            {displayExternalRunStatus(displayStatus)}
                          </strong>
                          <span style={{ fontSize: 12, color: '#64748b' }}>{r.progressPercent}%</span>
                        </div>
                        {r.companyCode ? (
                          <div style={{ fontSize: 12, color: '#475569', marginTop: 4 }}>
                            {r.companyCode}
                            {r.companyName ? ` · ${r.companyName}` : ''}
                          </div>
                        ) : null}
                        <div
                          style={{
                            fontSize: 12,
                            marginTop: 4,
                            color: failed > 0 ? '#b91c1c' : '#15803d',
                          }}
                        >
                          {statsLine}
                        </div>
                        <div style={{ fontSize: 13, marginTop: 4 }}>
                          {r.setsRequested.map(connectorLabel).join(', ') || '—'}
                        </div>
                        <small style={{ color: '#64748b' }}>{formatDate(r.startedAtUtc)}</small>
                        <br />
                        <small className={styles.gridSub}>{r.id.slice(0, 8)}…</small>
                      </button>
                    </li>
                    );
                  })}
                </ul>
              )}
            </TableCard>
          </div>

          <div className={styles.splitLayoutRight}>
            <div className={styles.splitPaneDetailScroll}>
              <TableCard>
                <div style={{ padding: 16 }}>
                  <h4 style={{ marginTop: 0 }}>Chi tiết run</h4>
                  {!selectedRunId ? (
                    <p style={{ color: '#64748b' }}>Chọn một run bên trái để xem tiến độ.</p>
                  ) : loadingDetail && !runDetail ? (
                    <p>Đang tải…</p>
                  ) : runDetail ? (
                    <JobExternalSyncRunDetailPanel runDetail={runDetail} />
                  ) : (
                    <p style={{ color: '#64748b' }}>Không tải được chi tiết run.</p>
                  )}
                </div>
              </TableCard>
            </div>

            <div className={styles.splitPaneCardFill}>
              <TableCard
                listShell
                header={
                  <div>
                    <h4 className={styles.listHeaderTitle}>Checkpoint theo chứng từ</h4>
                    <p className={styles.listHint}>
                      {runDetail?.checkpointSummary
                        ? formatCheckpointSummaryHint(runDetail.checkpointSummary)
                        : 'Tìm theo set, mã chứng từ hoặc trạng thái.'}
                    </p>
                    <JobsListToolbar
                      searchQuery={checkpointSearchQuery}
                      onSearchChange={setCheckpointSearchQuery}
                      searchPlaceholder="Tìm checkpoint…"
                      searchTestId="external-checkpoints-search"
                      onRefresh={
                        selectedRunId
                          ? () => {
                              loadCheckpoints(selectedRunId);
                            }
                          : undefined
                      }
                      refreshDisabled={!selectedRunId || loadingCheckpoints}
                      totalCount={checkpointsTotal}
                      filteredCount={filteredCheckpoints.length}
                      loading={loadingCheckpoints}
                      itemLabel="checkpoint"
                      extraActions={
                        <label style={{ fontSize: 13, display: 'flex', alignItems: 'center', gap: 8 }}>
                          Lọc
                          <select
                            value={checkpointStatus}
                            onChange={(e) => {
                              setCheckpointStatus(e.target.value);
                              setCheckpointPage(1);
                            }}
                            style={{ padding: '4px 8px', borderRadius: 4, border: '1px solid #cbd5e1' }}
                          >
                            <option value="">Tất cả</option>
                            <option value="Pending">Pending</option>
                            <option value="Processing">Processing</option>
                            <option value="Done">Done</option>
                            <option value="Failed">Failed</option>
                          </select>
                        </label>
                      }
                    />
                  </div>
                }
                footer={
                  selectedRunId && checkpointPages > 1 ? (
                    <Pagination
                      currentPage={checkpointPage}
                      totalPages={checkpointPages}
                      totalCount={checkpointsTotal}
                      pageSize={CHECKPOINT_PAGE_SIZE}
                      itemLabel="checkpoint"
                      onPageChange={setCheckpointPage}
                    />
                  ) : undefined
                }
              >
                {!selectedRunId ? (
                  <p className={styles.gridEmpty}>Chọn run để xem checkpoint.</p>
                ) : loadingCheckpoints && checkpoints.length === 0 ? (
                  <p className={styles.gridLoading}>Đang tải checkpoint…</p>
                ) : checkpointLoadError ? (
                  <p className={styles.gridEmpty} style={{ color: '#b91c1c' }}>
                    Không tải được checkpoint: {checkpointLoadError}
                  </p>
                ) : filteredCheckpoints.length === 0 ? (
                  <p className={styles.gridEmpty}>
                    {checkpointSearchQuery.trim()
                      ? 'Không tìm thấy checkpoint phù hợp trên trang này.'
                      : checkpointsTotal === 0
                        ? 'Run chưa có checkpoint — có thể search REVA chưa trả document hoặc run đang khởi tạo.'
                        : checkpointStatus
                          ? `Không có checkpoint trạng thái "${checkpointStatus}" trên trang này.`
                          : 'Không có checkpoint phù hợp bộ lọc.'}
                  </p>
                ) : (
                  <div className={styles.gridWrap}>
                    <table className={styles.gridTable}>
                      <thead>
                        <tr>
                          <th align="left">Loại</th>
                          <th align="left">Mã chứng từ</th>
                          <th align="left">Trạng thái</th>
                          <th align="left">Lỗi</th>
                          <th align="left">Cập nhật</th>
                        </tr>
                      </thead>
                      <tbody>
                        {filteredCheckpoints.map((c) => {
                          const errorText =
                            c.errorMessage ??
                            errorByDocument.get(c.documentKey) ??
                            null;
                          const canViewError = c.status === 'Failed';
                          return (
                          <tr key={c.id}>
                            <td>{connectorLabel(c.setName)}</td>
                            <td className={styles.gridMono}>
                              {canViewError ? (
                                <button
                                  type="button"
                                  className={styles.linkButton}
                                  onClick={() => openErrorDetail(c)}
                                  data-testid={`checkpoint-error-open-${c.documentKey}`}
                                >
                                  {c.documentKey}
                                </button>
                              ) : (
                                c.documentKey
                              )}
                            </td>
                            <td style={{ color: jobStatusColor(c.status), fontWeight: 600 }}>{c.status}</td>
                            <td style={{ fontSize: 12, maxWidth: 280 }}>
                              {canViewError ? (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: 4, alignItems: 'flex-start' }}>
                                  {errorText ? (
                                    <span style={{ color: '#b91c1c', whiteSpace: 'pre-wrap' }}>
                                      {truncateExternalErrorPreview(errorText)}
                                    </span>
                                  ) : (
                                    <span style={{ color: '#64748b' }}>—</span>
                                  )}
                                  <button
                                    type="button"
                                    className={styles.linkButton}
                                    onClick={() => openErrorDetail(c)}
                                  >
                                    Xem chi tiết lỗi
                                  </button>
                                </div>
                              ) : null}
                            </td>
                            <td style={{ color: '#64748b' }}>{formatDate(c.updatedAtUtc)}</td>
                          </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                )}
              </TableCard>
            </div>
          </div>
        </div>
      </div>

      <ExternalSyncCheckpointErrorModal
        isOpen={errorModalCheckpoint !== null}
        runId={selectedRunId ?? ''}
        checkpoint={errorModalCheckpoint}
        onClose={() => setErrorModalCheckpoint(null)}
      />
    </div>
  );
};

export default ExternalSyncRunsPage;
