import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { Select } from '../../../../ui';
import { useResponsive } from '../../../../hooks/useResponsive';
import { useFormOptions } from '../../../../hooks/useFormOptions';
import type { ActiveCompanyItem } from '../../../../services/company';
import styles from './AccountsFilters.module.css';

export interface AccountsFilterValues {
  search:       string;
  role:         string;
  statusFilter: 'all' | 'active' | 'inactive';
  companyId:    string;
  showDeleted:  boolean;
}

interface AccountsFiltersProps {
  filters:   AccountsFilterValues;
  onChange:  (f: AccountsFilterValues) => void;
  companies?: ActiveCompanyItem[];
}

export const AccountsFilters: React.FC<AccountsFiltersProps> = ({ filters, onChange, companies = [] }) => {
  const { isMobile } = useResponsive();
  const { accountRoleOptions, accountStatusOptions } = useFormOptions('accounts-list');

  const allRoleOptions = useMemo(
    () => [{ value: '', label: 'Tất cả vai trò' }, ...accountRoleOptions],
    [accountRoleOptions],
  );
  const allStatusOptions = useMemo(
    () => [{ value: 'all', label: 'Tất cả trạng thái' }, ...accountStatusOptions],
    [accountStatusOptions],
  );
  const allCompanyOptions = useMemo(
    () => [
      { value: '', label: 'Tất cả công ty' },
      ...companies.map((c) => ({ value: c.id, label: c.shortName ? `${c.shortName} - ${c.name}` : c.name })),
    ],
    [companies],
  );
  const [isExpanded, setIsExpanded] = useState(false);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const [dropdownStyle, setDropdownStyle] = useState<React.CSSProperties>({});

  const activeFilterCount = useMemo(() => {
    let count = 0;
    if (filters.role)                    count++;
    if (filters.statusFilter !== 'all')  count++;
    if (filters.companyId)               count++;
    if (filters.showDeleted)             count++;
    return count;
  }, [filters]);

  const hasActiveFilters = activeFilterCount > 0;

  const handleClear = () => {
    onChange({ ...filters, role: '', statusFilter: 'all', companyId: '', showDeleted: false });
    setIsExpanded(false);
  };

  const computeDropdownStyle = useCallback(() => {
    if (!buttonRef.current) return;
    const rect = buttonRef.current.getBoundingClientRect();
    const panelWidth = Math.min(300, window.innerWidth - 16);
    const centeredLeft = Math.max(8, (window.innerWidth - panelWidth) / 2);
    setDropdownStyle({ top: rect.bottom + 8, left: centeredLeft, width: panelWidth });
  }, []);

  const handleToggle = () => {
    if (!isExpanded) computeDropdownStyle();
    setIsExpanded((v) => !v);
  };

  useEffect(() => {
    if (!isExpanded) return;
    const close = () => setIsExpanded(false);
    window.addEventListener('scroll', close, { passive: true, capture: true });
    window.addEventListener('resize', close,  { passive: true });
    return () => {
      window.removeEventListener('scroll', close, { capture: true });
      window.removeEventListener('resize', close);
    };
  }, [isExpanded]);

  // ─── Mobile ──────────────────────────────────────────────────────────────
  if (isMobile) {
    return (
      <>
        {isExpanded && <div className={styles.filterBackdrop} onClick={() => setIsExpanded(false)} />}
        <div className={styles.container}>
          <div className={styles.mobileHeader}>
            <div className={styles.title}>Tài khoản</div>
            <div className={styles.filterDropdownWrapper}>
              <button
                ref={buttonRef}
                className={styles.filterToggle}
                onClick={handleToggle}
                aria-expanded={isExpanded}
                type="button"
              >
                <i className="fas fa-filter" />
                <span>Lọc</span>
                {activeFilterCount > 0 && (
                  <span className={styles.filterBadge}>{activeFilterCount}</span>
                )}
                <i className={`fas fa-chevron-${isExpanded ? 'up' : 'down'}`} />
              </button>
              {isExpanded && (
                <div className={styles.mobileFilters} style={dropdownStyle}>
                  <Select
                    value={filters.role}
                    onChange={(e) => onChange({ ...filters, role: e.target.value })}
                    options={allRoleOptions}
                    size="small"
                    fullWidth
                  />
                  <Select
                    value={filters.statusFilter}
                    onChange={(e) => onChange({ ...filters, statusFilter: e.target.value as AccountsFilterValues['statusFilter'] })}
                    options={allStatusOptions}
                    size="small"
                    fullWidth
                  />
                  {allCompanyOptions.length > 1 && (
                    <Select
                      value={filters.companyId}
                      onChange={(e) => onChange({ ...filters, companyId: e.target.value })}
                      options={allCompanyOptions}
                      size="small"
                      fullWidth
                    />
                  )}
                  <label className={styles.checkboxLabel}>
                    <input
                      type="checkbox"
                      checked={filters.showDeleted}
                      onChange={(e) => onChange({ ...filters, showDeleted: e.target.checked })}
                    />
                    <span>Hiển thị tài khoản đã xóa</span>
                  </label>
                  {hasActiveFilters && (
                    <button className={styles.clearFiltersButton} onClick={handleClear} type="button">
                      <i className="fas fa-times-circle" />
                      <span>Xóa bộ lọc</span>
                    </button>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </>
    );
  }

  // ─── Desktop ──────────────────────────────────────────────────────────────
  return (
    <div className={styles.container}>
      <div className={styles.title}>Tài khoản</div>
      <div className={styles.filters}>
        <div className={styles.searchWrapper}>
          <i className={`fas fa-search ${styles.searchIcon}`} />
          <input
            type="text"
            className={styles.searchInput}
            placeholder="Tìm theo tên, email, username..."
            value={filters.search}
            onChange={(e) => onChange({ ...filters, search: e.target.value })}
          />
        </div>
        <Select
          value={filters.role}
          onChange={(e) => onChange({ ...filters, role: e.target.value })}
          options={allRoleOptions}
          size="small"
        />
        <Select
          value={filters.statusFilter}
          onChange={(e) => onChange({ ...filters, statusFilter: e.target.value as AccountsFilterValues['statusFilter'] })}
          options={allStatusOptions}
          size="small"
        />
        {allCompanyOptions.length > 1 && (
          <Select
            value={filters.companyId}
            onChange={(e) => onChange({ ...filters, companyId: e.target.value })}
            options={allCompanyOptions}
            size="small"
          />
        )}
        <label className={styles.checkboxLabel}>
          <input
            type="checkbox"
            checked={filters.showDeleted}
            onChange={(e) => onChange({ ...filters, showDeleted: e.target.checked })}
          />
          <span>Đã xóa</span>
        </label>
        {hasActiveFilters && (
          <button className={styles.clearFiltersButtonDesktop} onClick={handleClear} type="button">
            <i className="fas fa-times-circle" />
            <span>Xóa bộ lọc</span>
          </button>
        )}
      </div>
    </div>
  );
};
