import React from 'react';
import { Input } from '../../ui';
import ConnectorFieldLabel from './ConnectorFieldLabel';
import styles from './DataSyncSetConfigPage.module.css';

type Props = Omit<React.ComponentProps<typeof Input>, 'label'> & {
  label: string;
  tooltip?: string;
  fieldId?: string;
  required?: boolean;
};

export const ConnectorFormField: React.FC<Props> = ({
  label,
  tooltip,
  fieldId,
  required,
  ...inputProps
}) => (
  <div className={styles.labeledField}>
    <ConnectorFieldLabel htmlFor={fieldId} label={label} tooltip={tooltip} required={required} />
    <Input {...inputProps} label="" aria-label={label} />
  </div>
);

export default ConnectorFormField;
